"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["37095"],{53392(s){s.exports=JSON.parse('{"tag":{"label":"content","permalink":"/sysanalyst-kb.github.io/docs/tags/content","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":2,"items":[{"id":"specialization/gamedev-liveops","title":"LiveOps \u2014 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0436\u0438\u0432\u044B\u043C \u043F\u0440\u043E\u0434\u0443\u043A\u0442\u043E\u043C","description":"LiveOps \u2014 \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E\u0435 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0438\u0433\u0440\u043E\u0439 \u043F\u043E\u0441\u043B\u0435 \u0437\u0430\u043F\u0443\u0441\u043A\u0430: \u0438\u0432\u0435\u043D\u0442\u044B, \u0431\u043E\u0435\u0432\u044B\u0435 \u043F\u0440\u043E\u043F\u0443\u0441\u043A\u0438 (Battle Pass), \u0435\u0436\u0435\u0434\u043D\u0435\u0432\u043D\u044B\u0435 \u0437\u0430\u0434\u0430\u043D\u0438\u044F, \u0441\u0435\u0437\u043E\u043D\u043D\u044B\u0439 \u043A\u043E\u043D\u0442\u0435\u043D\u0442 \u0438 \u0440\u043E\u0442\u0430\u0446\u0438\u044F \u043C\u0430\u0433\u0430\u0437\u0438\u043D\u0430. \u0426\u0435\u043B\u044C \u2014 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044C \u0438\u043D\u0442\u0435\u0440\u0435\u0441 \u0438\u0433\u0440\u043E\u043A\u043E\u0432, \u0443\u0432\u0435\u043B\u0438\u0447\u0438\u0432\u0430\u0442\u044C retention \u0438 \u0434\u043E\u0445\u043E\u0434 \u043D\u0430 \u043F\u0440\u043E\u0442\u044F\u0436\u0435\u043D\u0438\u0438 \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u0438 \u043B\u0435\u0442. \u0425\u043E\u0440\u043E\u0448\u0438\u0439 LiveOps \u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442 \u0438\u0433\u0440\u0443 \u0432 \xab\u0436\u0438\u0432\u043E\u0439 \u0441\u0435\u0440\u0432\u0438\u0441\xbb (Games-as-a-Service), \u0433\u0434\u0435 \u043A\u0430\u0436\u0434\u044B\u0439 \u0434\u0435\u043D\u044C \u0435\u0441\u0442\u044C \u043F\u0440\u0438\u0447\u0438\u043D\u0430 \u0437\u0430\u0439\u0442\u0438. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u043A\u043E\u043D\u0442\u0435\u043D\u0442-\u043A\u0430\u043B\u0435\u043D\u0434\u0430\u0440\u044C, \u0444\u043E\u0440\u043C\u0443\u043B\u044B \u0438\u0432\u0435\u043D\u0442\u043E\u0432, \u043C\u0435\u0442\u0440\u0438\u043A\u0438 \u0438\u0445 \u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u0438 \u0438 \u0441\u0432\u044F\u0437\u044C \u0441 \u044D\u043A\u043E\u043D\u043E\u043C\u0438\u043A\u043E\u0439 \u0438\u0433\u0440\u044B.","permalink":"/sysanalyst-kb.github.io/docs/specialization/gamedev-liveops"},{"id":"specialization/socnet-path","title":"\u0421\u043E\u0446\u0441\u0435\u0442\u0438 \u0438 \u043A\u043E\u043D\u0442\u0435\u043D\u0442\u043D\u044B\u0435 \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u044B \u2014 \u0440\u043E\u043B\u044C, \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430, \u043F\u0443\u0442\u044C","description":"\u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0441\u043E\u0446\u0441\u0435\u0442\u0435\u0439 \u0438 \u043A\u043E\u043D\u0442\u0435\u043D\u0442\u043D\u044B\u0445 \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0441 \u043B\u0435\u043D\u0442\u043E\u0439 (feed), \u043C\u0435\u0441\u0441\u0435\u043D\u0434\u0436\u0435\u0440\u0430\u043C\u0438, \u043C\u043E\u0434\u0435\u0440\u0430\u0446\u0438\u0435\u0439, \u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u043C \u0433\u0440\u0430\u0444\u043E\u043C, \u043C\u043E\u043D\u0435\u0442\u0438\u0437\u0430\u0446\u0438\u0435\u0439 (\u0440\u0435\u043A\u043B\u0430\u043C\u0430/\u043F\u043E\u0434\u043F\u0438\u0441\u043A\u0438), \u043A\u043E\u043D\u0442\u0435\u043D\u0442\u043D\u043E\u0439 \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u043E\u0439 (\u0432\u0438\u0434\u0435\u043E, \u043C\u0443\u0437\u044B\u043A\u0430, stories) \u0438 API/SDK \u0434\u043B\u044F \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0447\u0438\u043A\u043E\u0432. \u041A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u0432\u044B\u0437\u043E\u0432\u044B \u2014 \u043C\u0430\u0441\u0448\u0442\u0430\u0431 (\u043C\u0438\u043B\u043B\u0438\u0430\u0440\u0434\u044B \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u0435\u0439), real-time, AI-\u043C\u043E\u0434\u0435\u0440\u0430\u0446\u0438\u044F (ASR/NSFW), \u0440\u0435\u043A\u043E\u043C\u0435\u043D\u0434\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B. \u0418\u043D\u0434\u0443\u0441\u0442\u0440\u0438\u044F \u043C\u0435\u043D\u044F\u0435\u0442\u0441\u044F \u043A\u0430\u0436\u0434\u044B\u0435 2-3 \u0433\u043E\u0434\u0430: TikTok \u043F\u0435\u0440\u0435\u0432\u0435\u0440\u043D\u0443\u043B feed, Clubhouse \u2014 \u0430\u0443\u0434\u0438\u043E, Threads \u2014 \u043C\u0438\u043A\u0440\u043E\u0431\u043B\u043E\u0433\u0438\u043D\u0433.","permalink":"/sysanalyst-kb.github.io/docs/specialization/socnet-path"}],"unlisted":false}}')}}]);